import { useState } from "react";

export default function Register() {
  const [form, setForm] = useState({});

  const submit = async () => {
    await fetch("http://192.168.1.40:5000/register", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(form),
    });

    alert("Registered successfully");
  };

  return (
    <div className="card">
      <h2>Register</h2>

      <input placeholder="Name" onChange={(e) => setForm({ ...form, name: e.target.value })} />
      <input placeholder="Aadhaar" onChange={(e) => setForm({ ...form, aadhaar: e.target.value })} />
      <input type="date" onChange={(e) => setForm({ ...form, dob: e.target.value })} />
      <input placeholder="Center ID" onChange={(e) => setForm({ ...form, center_id: e.target.value })} />
      <input type="date" onChange={(e) => setForm({ ...form, date: e.target.value })} />

      <button onClick={submit}>Submit</button>
    </div>
  );
}
